mapper.select:
SELECT id, aggregate_type, aggregate_id, event_type, payload_json, status,
       attempts, available_at, published_at, error_message, created_at, updated_at
FROM outbox_events
WHERE status = 'pending'

    AND (
        created_at > (SELECT created_at FROM outbox_events WHERE id = #{afterEventId})
        OR (
            created_at = (SELECT created_at FROM outbox_events WHERE id = #{afterEventId})
            AND id > #{afterEventId}
        )
    )

ORDER BY created_at ASC, id ASC
LIMIT #{limit}
